import { GoogleGenAI, Tool } from "@google/genai";
import { SearchResponse, CaseAnalysis } from "../types";

// Helper to ensure API key exists
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please ensure process.env.API_KEY is available.");
  }
  return new GoogleGenAI({ apiKey });
};

/**
 * Searches for court cases using the `googleSearch` tool for real-time grounding.
 */
export const searchCases = async (query: string): Promise<SearchResponse> => {
  const ai = getClient();

  // Using gemini-3-flash-preview for speed and search capability
  const modelId = 'gemini-3-flash-preview'; 

  const prompt = `
    Search for court cases worldwide related to: "${query}".

    If the query is vague, try to identify famous cases that match.
    Provide a comprehensive overview of the most relevant cases found.
    For each case, clearly state:
    1. Case Name
    2. Case Number (if available)
    3. Jurisdiction/Court
    4. Date
    5. A concise summary of the holding/verdict.

    Structure the response in clean Markdown. Use bolding for Case Names.
    Do not invent cases; strictly use the Google Search grounding data provided.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} } as Tool],
      },
    });

    const text = response.text || "No results found.";
    // Safe extraction of grounding chunks
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      groundingChunks: groundingChunks.map((chunk: any) => ({
        web: chunk.web ? { uri: chunk.web.uri, title: chunk.web.title } : undefined
      })).filter((c: any) => c.web !== undefined)
    };

  } catch (error) {
    console.error("Search failed:", error);
    throw error;
  }
};

/**
 * Performs a deeper analysis of a specific legal concept or text using the Pro model.
 * This does not use Google Search, but relies on the model's internal reasoning.
 */
export const analyzeLegalConcept = async (context: string): Promise<CaseAnalysis> => {
  const ai = getClient();
  // Using gemini-3-pro-preview for complex reasoning
  const modelId = 'gemini-3-pro-preview';

  const prompt = `
    Analyze the following legal text or case summary and provide a structured breakdown.

    Context:
    "${context}"

    Return the result in JSON format with the following keys:
    - summary: A professional executive summary (max 3 sentences).
    - keyPoints: An array of strings representing the key legal arguments or facts.
    - implications: A string explaining the broader legal or social implications of this.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text) as CaseAnalysis;

  } catch (error) {
    console.error("Analysis failed:", error);
    // Fallback if JSON parsing fails or API errors
    return {
      summary: "Could not generate analysis.",
      keyPoints: ["Analysis unavailable"],
      implications: "Please try again."
    };
  }
};

