      setSortOption('relevance');
      setJurisdictionFilter('ALL');
    } catch (err: any) {
      console.error(err);
      setErrorMsg("Unable to complete search. Please check your connection or try again.");
      setStatus(SearchStatus.ERROR);
    }
  };

  const handleAnalyze = async (caseData: Case) => {
    setIsModalOpen(true);
    setAnalysisLoading(true);
    setAnalysisResult(null);

    try {
      // Construct a rich context for the analysis model
      const context = `
        Case Name: ${caseData.name}
        Citation: ${caseData.citation}
        Jurisdiction: ${caseData.jurisdiction}
        Date: ${caseData.date}
        Summary: ${caseData.summary}
      `;
      const result = await analyzeLegalConcept(context);
      setAnalysisResult(result);
    } catch (err) {
      console.error(err);
    } finally {
      setAnalysisLoading(false);
    }
  };

  // Derived State: Jurisdictions List
  const availableJurisdictions = useMemo(() => {
    const juris = new Set(cases.map(c => c.jurisdiction).filter(Boolean));
    return Array.from(juris).sort();
  }, [cases]);

  // Derived State: Filtered & Sorted Cases
  const filteredCases = useMemo(() => {
    let result = [...cases];

    // Filter
    if (jurisdictionFilter !== 'ALL') {
      result = result.filter(c => c.jurisdiction === jurisdictionFilter);
    }

    // Sort
    if (sortOption === 'date_desc') {
      result.sort((a, b) => (new Date(b.date || 0).getTime()) - (new Date(a.date || 0).getTime()));
    } else if (sortOption === 'date_asc') {
      result.sort((a, b) => (new Date(a.date || 0).getTime()) - (new Date(b.date || 0).getTime()));
    }
    // 'relevance' assumes API order is best, no sort needed.

    return result;
  }, [cases, jurisdictionFilter, sortOption]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-grow flex flex-col">
        <SearchArea onSearch={handleSearch} isSearching={status === SearchStatus.SEARCHING} />

        {/* Error State */}
        {status === SearchStatus.ERROR && (
          <div className="max-w-4xl mx-auto px-4 mt-8 w-full">
            <div className="bg-red-50 border border-red-200 rounded-lg p-4 flex items-center text-red-700">
              <AlertTriangle className="h-5 w-5 mr-3" />
              {errorMsg}
            </div>
          </div>
        )}

        {/* Results State */}
        {status === SearchStatus.SUCCESS && (
          <>
            <ResultsToolbar 
              totalResults={filteredCases.length}
              sortOption={sortOption}
              onSortChange={setSortOption}
              jurisdictions={availableJurisdictions}
              selectedJurisdiction={jurisdictionFilter}
              onJurisdictionChange={setJurisdictionFilter}
            />

            <div className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">
              <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 items-start">

                {/* Left Column: Case Cards */}
                <div className="lg:col-span-3">
                  {filteredCases.length === 0 ? (
                    <div className="text-center py-20 bg-white rounded-2xl border border-slate-200 border-dashed">
                      <BookOpen className="h-10 w-10 text-slate-300 mx-auto mb-4" />
                      <h3 className="text-lg font-medium text-slate-900">No cases found</h3>
                      <p className="text-slate-500">Try adjusting your filters or search query.</p>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      {filteredCases.map((caseItem, index) => (
                        <CaseCard 
                          key={`${caseItem.name}-${index}`} 
                          data={caseItem} 
                          onAnalyze={handleAnalyze} 
                        />
                      ))}
                    </div>
                  )}
                </div>

                {/* Right Column: Sources Sticky Sidebar */}
                <div className="lg:col-span-1 space-y-6">
                  <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5 sticky top-36">
                    <h3 className="text-xs font-bold text-slate-900 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">
                      Verified Sources
                    </h3>

                    {groundingSources.length === 0 ? (
                      <p className="text-sm text-slate-500 italic">No direct web sources linked.</p>
                    ) : (
                      <ul className="space-y-3">
                        {groundingSources.map((source, index) => (
                          <li key={index} className="group">
                            <a 
                              href={source.web?.uri} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="block p-3 rounded-lg bg-slate-50 hover:bg-brand-50 border border-transparent hover:border-brand-200 transition-all duration-200"
                            >
                              <div className="flex justify-between items-start mb-1">
                                <span className="text-[10px] font-bold text-brand-600 bg-brand-50 px-1.5 py-0.5 rounded">
                                  REF {index + 1}
                                </span>
                                <ExternalLink className="h-3 w-3 text-slate-400 group-hover:text-brand-500" />
                              </div>
                              <p className="text-xs text-slate-800 font-medium line-clamp-2 leading-snug">
                                {source.web?.title || "Untitled Source"}
                              </p>
                            </a>
                          </li>
                        ))}
                      </ul>
                    )}

                    <div className="mt-6 pt-4 border-t border-slate-100">
                      <p className="text-[10px] text-slate-400 leading-tight">
                        LexiFind aggregates public legal information. Verify all citations with official court records.
                      </p>
                    </div>
                  </div>
                </div>

              </div>
            </div>
          </>
        )}
      </main>

      {/* Analysis Modal */}
      <AnalysisModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        analysis={analysisResult}
        isLoading={analysisLoading}
      />
    </div>
  );
};

