// Helper to ensure API key exists
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please ensure process.env.API_KEY is available.");
  }
  return new GoogleGenAI({ apiKey });
};

/**
 * Searches for court cases using the `googleSearch` tool and returns structured JSON.
 */
export const searchCases = async (query: string): Promise<SearchResponse> => {
  const ai = getClient();
  const modelId = 'gemini-3-flash-preview'; 

  const prompt = `
    Search for court cases worldwide related to: "${query}".

    Goal: Identify real, specific court cases that match the query and provide links to their full text/judgment where available.

    Instructions:
    1. Use Google Search to find accurate case details.
    2. Return a list of cases found.
    3. For each case, extract:
       - Jurisdiction
       - Date (YYYY-MM-DD or YYYY)
       - Case Number (Citation)
       - Brief summary
       - A direct URL to the full judgment text, PDF, or official case report (e.g. from Justia, BAILII, CanLII, CourtListener, or official court websites).
    4. Assign relevant tags (e.g., "Criminal", "Civil", "IP", "Constitutional").
    5. If the exact date is unknown, estimate the year based on the search results.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} } as Tool],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            cases: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING, description: "Name of the case (e.g., Roe v. Wade)" },
                  citation: { type: Type.STRING, description: "Case number or official citation" },
                  jurisdiction: { type: Type.STRING, description: "Court or Jurisdiction (e.g., US Supreme Court, UK High Court)" },
                  date: { type: Type.STRING, description: "Date of decision in YYYY-MM-DD or YYYY format" },
                  summary: { type: Type.STRING, description: "Concise summary of the holding" },
                  tags: { type: Type.ARRAY, items: { type: Type.STRING } },
                  fullTextUrl: { type: Type.STRING, description: "URL to the full text judgment or official page" }
                }
              }
            }
          }
        }
      },
    });

    // Parse the JSON response
    const jsonText = response.text || '{ "cases": [] }';
    let parsedData: { cases: Case[] } = { cases: [] };

    try {
      parsedData = JSON.parse(jsonText);
    } catch (e) {
      console.warn("Failed to parse JSON directly, attempting cleanup", e);
      // Fallback cleanup if model includes markdown blocks despite mimeType
      const cleanJson = jsonText.replace(/```json/g, '').replace(/```/g, '');
      parsedData = JSON.parse(cleanJson);
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      cases: parsedData.cases || [],
      groundingChunks: groundingChunks.map((chunk: any) => ({
        web: chunk.web ? { uri: chunk.web.uri, title: chunk.web.title } : undefined
      })).filter((c: any) => c.web !== undefined)
    };

  } catch (error) {
    console.error("Search failed:", error);
    throw error;
  }
};

